import React, { useState, useEffect } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const MyBookings = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedStatusTab, setSelectedStatusTab] = useState('Active');
  const [selectedStatusDropdown, setSelectedStatusDropdown] = useState('all');
  const [currentSearch, setCurrentSearch] = useState('');

  // Mock booking data - using car images from BrowseCars
  const mockBookings = [
    {
      id: 1,
      bookingId: 'BR1024',
      carName: 'Toyota Wigo',
      carImage: 'https://imgcdnblog.carmudi.com.ph/wp-content/uploads/2021/07/14150638/Toyota-Wigo-2.jpg',
      startDate: '2026-02-26',
      endDate: '2026-02-28',
      pickupLocation: 'Sta. Rita, Samar',
      status: 'Active',
      type: 'Booking',
      totalPrice: 1500
    },
    {
      id: 2,
      bookingId: 'BR1186',
      carName: 'Toyota Vios',
      carImage: 'https://i.pinimg.com/736x/55/41/b3/5541b37eb9bd4d6280dab75236aa6cc2.jpg',
      startDate: '2026-02-25',
      endDate: '2026-02-29',
      pickupLocation: 'Sta. Rita, Samar',
      status: 'Upcoming',
      type: 'Upcoming',
      totalPrice: 1900,
      isFavorite: true
    },
    {
      id: 3,
      bookingId: 'BR1201',
      carName: 'Toyota Hilux',
      carImage: 'https://img.lazcdn.com/g/p/c4d179ffaa3d38410d45b92fcc68587b.jpg_960x960q80.jpg_.webp',
      startDate: '2026-01-03',
      endDate: '2026-01-06',
      pickupLocation: 'Tacloban City, Leyte',
      status: 'Past',
      type: 'Past',
      totalPrice: 2500,
      rating: 5,
      completedCount: 16
    }
  ];

  useEffect(() => {
    // Simulate loading data
    setTimeout(() => {
      setBookings(mockBookings);
      setLoading(false);
    }, 500);
  }, []);

  const handleCancelBooking = (bookingId) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      setBookings(bookings.map(booking => 
        booking.id === bookingId 
          ? { ...booking, status: 'cancelled' } 
          : booking
      ));
    }
  };

  const filterBookings = () => {
    const searchText = currentSearch.trim().toLowerCase();

    return bookings.filter(card => {
      const cardStatus = card.status;
      const cardType = card.type;
      const bookingID = card.bookingId.toLowerCase();
      const carModel = card.carName.toLowerCase();
      const location = card.pickupLocation.toLowerCase();

      // Check status tab match (exact match)
      const statusTabMatch = selectedStatusTab === 'All' || cardStatus.toLowerCase() === selectedStatusTab.toLowerCase();

      // Check status select filter (dropdown)
      const statusDropdownMatch = selectedStatusDropdown === 'all' || cardType.toLowerCase() === selectedStatusDropdown.toLowerCase();

      // Check search filter
      const searchMatch = bookingID.includes(searchText) || carModel.includes(searchText) || location.includes(searchText);

      return statusTabMatch && statusDropdownMatch && searchMatch;
    });
  };

  const filteredBookings = filterBookings();

  const formatDate = (dateStr) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
  };

  const getStatusClass = (status) => {
    switch(status.toLowerCase()) {
      case 'active':
        return 'status-label active';
      case 'upcoming':
        return 'status-label upcoming';
      case 'past':
        return 'status-label past';
      case 'completed':
        return 'status-label completed';
      case 'booking':
        return 'status-label booking';
      default:
        return 'status-label';
    }
  };

  const renderStars = (rating) => {
    return Array.from({ length: 5 }, (_, i) => (
      <svg key={i} aria-hidden="true" viewBox="0 0 24 24" fill={i < rating ? "#ffc107" : "none"} stroke="#ffc107" strokeWidth="2" focusable="false">
        <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z"/>
      </svg>
    ));
  };

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <h2 style={styles.pageTitle}>My Bookings</h2>

        <div className="filter-bar" role="search" aria-label="Booking filters and search" style={styles.filterBar}>
          <div className="status-tabs" role="tablist" aria-label="Filter bookings by status" style={styles.statusTabs}>
            {['Active', 'Upcoming', 'Past'].map(status => (
              <button
                key={status}
                type="button"
                className={selectedStatusTab === status ? 'active' : 'inactive'}
                style={selectedStatusTab === status ? styles.statusTabActive : styles.statusTabInactive}
                onClick={() => setSelectedStatusTab(status)}
                role="tab"
                aria-selected={selectedStatusTab === status}
              >
                {status}
              </button>
            ))}
          </div>

          <select 
            className="status-select" 
            aria-label="Filter by Statuses" 
            title="Filter by Statuses"
            style={styles.statusSelect}
            value={selectedStatusDropdown}
            onChange={(e) => setSelectedStatusDropdown(e.target.value)}
          >
            <option value="all">All Statuses</option>
            <option value="Booking">Booking</option>
            <option value="Upcoming">Upcoming</option>
            <option value="Past">Past</option>
            <option value="Completed">Completed</option>
            <option value="Active">Active</option>
          </select>

          <input
            type="search"
            className="search-input"
            placeholder="Search by booking ID, car or location..."
            aria-label="Search bookings"
            spellCheck="false"
            style={styles.searchInput}
            value={currentSearch}
            onChange={(e) => setCurrentSearch(e.target.value)}
          />

          <button type="button" className="filter-btn" aria-label="Filter bookings" style={styles.filterBtn}>
            Filter
          </button>
        </div>

        {loading ? (
          <div style={styles.loading}>Loading bookings...</div>
        ) : filteredBookings.length === 0 ? (
          <div style={styles.emptyState}>
            <p>No bookings found</p>
          </div>
        ) : (
          <section className="bookings-container" id="bookingsList" aria-live="polite" style={styles.bookingsContainer}>
            {filteredBookings.map(booking => (
              <article 
                key={booking.id} 
                className={`booking-card ${booking.status === 'Active' ? 'booking-badge' : ''}`}
                data-status={booking.status}
                data-type={booking.type}
                data-bookingid={booking.bookingId}
                data-car={booking.carName}
                data-location={booking.pickupLocation}
                data-start={booking.startDate}
                data-end={booking.endDate}
                data-price={booking.totalPrice}
                style={styles.bookingCard}
              >
                <div className="car-image-container" aria-hidden="true" style={styles.carImageContainer}>
                  <img src={booking.carImage} alt={booking.carName} loading="lazy" style={styles.carImage} />
                  {booking.status === 'Upcoming' && (
                    <span className="booking-pill" style={styles.bookingPill} aria-label="Booking status Booking">Booking</span>
                  )}
                </div>
                
                <div className="main-info" style={styles.mainInfo}>
                  <div>
                    <strong className="booking-id" style={styles.bookingId}>{booking.bookingId}</strong>
                    <span aria-label="Car model" style={styles.carModel}>{booking.carName}</span>
                    {booking.isFavorite && (
                      <span className="favorite-heart" aria-hidden="true" title="Favorite" style={styles.favoriteHeart}>♥</span>
                    )}
                  </div>
                  
                  {booking.rating && (
                    <div className="rating" aria-label={`${booking.rating} star rating with ${booking.completedCount} complete bookings`} style={styles.rating}>
                      {renderStars(booking.rating)}
                      <small>{booking.completedCount} Complete</small>
                    </div>
                  )}
                  
                  <div className="icon-text date-range" aria-label={`Booking Dates ${formatDate(booking.startDate)} to ${formatDate(booking.endDate)}`} style={styles.dateRange}>
                    <svg fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24" aria-hidden="true" focusable="false" style={styles.icon}>
                      <rect x="3" y="4" width="18" height="18" rx="2" ry="2"/>
                      <line x1="16" y1="2" x2="16" y2="6"/>
                      <line x1="8" y1="2" x2="8" y2="6"/>
                      <line x1="3" y1="10" x2="21" y2="10"/>
                    </svg>
                    {formatDate(booking.startDate)} - {formatDate(booking.endDate)}
                  </div>
                </div>
                
                <div className="main-info" aria-label={`Pickup location ${booking.pickupLocation}`} style={styles.mainInfo}>
                  <div className="icon-text" style={styles.iconText}>
                    <svg fill="none" stroke="#444" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24" aria-hidden="true" focusable="false" style={styles.icon}>
                      <path d="M12 21c-4.97 0-9-7-9-10a9 9 0 1 1 18 0c0 3-4.03 10-9 10z"/>
                      <circle cx="12" cy="11" r="2"/>
                    </svg>
                    {booking.pickupLocation}
                  </div>
                </div>

                <div className="actions" role="group" aria-label="Booking actions" style={styles.actions}>
                  <span className={getStatusClass(booking.status)} aria-label={`Booking status ${booking.status}`}>
                    {booking.status} {booking.status === 'Active' && '...'}
                  </span>
                  <button className="view-details-btn" type="button" aria-label={`View details for booking ${booking.bookingId}`} style={styles.viewDetailsBtn}>
                    View Details
                  </button>
                  <div className="cancel-rebook-container" style={styles.cancelRebookContainer}>
                    {booking.status === 'Past' || booking.status === 'Completed' ? (
                      <>
                        <button type="button" className="rebook-btn" aria-haspopup="true" aria-expanded="false" aria-label={`Rebook booking ${booking.bookingId}`} style={styles.rebookBtn}>
                          Rebook
                        </button>
                        <div className="dropdown-arrow" aria-hidden="true" tabIndex="-1" style={styles.dropdownArrow}>▼</div>
                      </>
                    ) : (
                      <>
                        <button 
                          type="button" 
                          className="cancel-btn" 
                          aria-haspopup="true" 
                          aria-expanded="false" 
                          aria-label={`Cancel booking ${booking.bookingId}`} 
                          style={styles.cancelBtn}
                          onClick={() => handleCancelBooking(booking.id)}
                        >
                          Cancel
                        </button>
                        <div className="dropdown-arrow" aria-hidden="true" tabIndex="-1" style={styles.dropdownArrow}>▼</div>
                      </>
                    )}
                  </div>
                  {booking.status === 'Past' && (
                    <span className="status-label completed" aria-label="Completed booking status" style={styles.completedLabel}>
                      Completed
                    </span>
                  )}
                </div>
              </article>
            ))}
          </section>
        )}

        {/* Info row */}
        <section className="info-row" aria-label="Booking benefits" style={styles.infoRow}>
          <div style={styles.infoBox}>
            <svg viewBox="0 0 64 64" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={styles.infoIcon}>
              <path d="M9 52h46M12 44h40M16 36h32M20 28h24M24 20h16" />
            </svg>
            <div>
              <strong style={styles.infoTitle}>Affordable Rates</strong>
              <span style={styles.infoSubtitle}>Great prices on all vehicle types</span>
            </div>
          </div>
          <div style={styles.infoBox}>
            <svg viewBox="0 0 50 50" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={styles.infoIcon}>
              <circle cx="25" cy="25" r="24" />
              <path d="M21 18v9l6 3" />
              <path d="M25 31v-8" />
              <path d="M15 15h20" />
              <path d="M12 38h10" />
              <path d="M33 38h7" />
            </svg>
            <div>
              <strong style={styles.infoTitle}>Safety &amp; Security</strong>
              <span style={styles.infoSubtitle}>Well-maintained and safe rental cars</span>
            </div>
          </div>
          <div style={styles.infoBox}>
            <svg viewBox="0 0 22 22" fill="none" stroke="currentColor" strokeWidth="2" strokeLinejoin="round" strokeLinecap="round" aria-hidden="true" focusable="false" style={styles.infoIcon}>
              <path d="M2 16v1a5 5 0 0 0 10 0v-1" />
              <path d="M17 12v-6a5 5 0 0 0-10 0v6" />
              <line x1="0" y1="7" x2="22" y2="7" />
              <line x1="4" y1="12" x2="18" y2="12" />
              <line x1="7" y1="16" x2="15" y2="16" />
            </svg>
            <div>
              <strong style={styles.infoTitle}>Easy Booking</strong>
